```javascript
const express = require('express');
const app = express();

// Logging middleware - runs on every request
const requestLogger = (req, res, next) => {
  const timestamp = new Date().toISOString();
  const method = req.method;
  const url = req.url;

  console.log(`[${timestamp}] ${method} ${url}`);

  next(); // Pass control to next middleware
};

// Authentication middleware
const requireAuth = (req, res, next) => {
  // Get token from header
  const token = req.headers.authorization;

  // Check if token exists
  if (!token) {
    return res.status(401).json({ 
      error: 'Authentication required' 
    });
  }

  // Verify token (simplified - in real app, verify JWT)
  if (token === 'Bearer valid-token-123') {
    // Token is valid, attach user info to request
    req.user = { id: 1, name: 'John Doe' };
    next(); // Proceed to route handler
  } else {
    return res.status(403).json({ 
      error: 'Invalid token' 
    });
  }
};

// Apply logging middleware globally
app.use(requestLogger);

// Public route - no authentication needed
app.get('/api/public', (req, res) => {
  res.json({ message: 'This is public data' });
});

// Protected route - authentication required
app.get('/api/dashboard', requireAuth, (req, res) => {
  res.json({ 
    message: 'Welcome to your dashboard',
    user: req.user 
  });
});

app.listen(3000);
```

**Testing:**

```bash
# Public route - works without token
curl http://localhost:3000/api/public

# Protected route - fails without token
curl http://localhost:3000/api/dashboard
# Response: {"error":"Authentication required"}

# Protected route - succeeds with valid token
curl http://localhost:3000/api/dashboard \
  -H "Authorization: Bearer valid-token-123"
# Response: {"message":"Welcome to your dashboard","user":{...}}
```

**Middleware order matters**: Logging runs first, then authentication when needed.

**app.use()** is for **middleware** — functions that run for requests before they reach route handlers. It can match all methods (GET, POST, etc.) and all paths or specific paths.

**app.get()** is for **route handlers** — specifically handles GET requests to a defined path.

**Key Differences:**

| Feature | app.use() | app.get() |
|---------|-----------|----------|
| **Purpose** | Middleware | Route handler |
| **HTTP Methods** | All (GET, POST, etc.) | Only GET |
| **Path Matching** | Prefix matching | Exact matching |
| **next() Required** | Yes (or send response) | No (sends response) |

**Examples:**

```javascript
// app.use() - Middleware (runs for all methods)
app.use(express.json()); // Runs for ALL requests

app.use('/api', (req, res, next) => {
  console.log('API request');
  next(); // MUST call next() or send response
});

// This matches /api, /api/users, /api/users/42, etc.
app.use('/api', (req, res, next) => {
  console.log('Matches any path starting with /api');
  next();
});

// app.get() - Route handler (only GET requests)
app.get('/api/users', (req, res) => {
  res.json({ users: [] }); // Sends response, no next() needed
});

// This matches ONLY /api/users with GET method
```

**When to use app.use():**
- Applying middleware globally (logging, parsing, CORS)
- Mounting routers
- Setting up error handlers

**When to use app.get():**
- Handling specific GET requests
- Retrieving data from API endpoints
- Serving specific pages

**Practical Example:**

```javascript
// Middleware with app.use()
app.use(express.json()); // Parse JSON for all requests
app.use(requestLogger); // Log all requests

// Route handlers with app.get()
app.get('/api/products', getProducts); // GET products
app.post('/api/products', createProduct); // POST new product
```

```javascript
const express = require('express');
const app = express();
const PORT = 3000;

// Middleware
app.use(express.json());

// In-memory database (array)
let todos = [
  { id: 1, title: 'Learn Express', completed: false },
  { id: 2, title: 'Build API', completed: false }
];

let nextId = 3;

// GET all todos
app.get('/api/todos', (req, res) => {
  res.status(200).json({
    success: true,
    count: todos.length,
    data: todos
  });
});

// GET single todo by ID
app.get('/api/todos/:id', (req, res) => {
  const todo = todos.find(t => t.id === parseInt(req.params.id));

  if (!todo) {
    return res.status(404).json({
      success: false,
      error: 'Todo not found'
    });
  }

  res.status(200).json({
    success: true,
    data: todo
  });
});

// POST - Create new todo
app.post('/api/todos', (req, res) => {
  const { title } = req.body;

  // Validation
  if (!title || title.trim() === '') {
    return res.status(400).json({
      success: false,
      error: 'Title is required'
    });
  }

  const newTodo = {
    id: nextId++,
    title: title.trim(),
    completed: false
  };

  todos.push(newTodo);

  res.status(201).json({
    success: true,
    data: newTodo
  });
});

// PUT - Update todo
app.put('/api/todos/:id', (req, res) => {
  const todo = todos.find(t => t.id === parseInt(req.params.id));

  if (!todo) {
    return res.status(404).json({
      success: false,
      error: 'Todo not found'
    });
  }

  const { title, completed } = req.body;

  // Validation
  if (title !== undefined) {
    if (title.trim() === '') {
      return res.status(400).json({
        success: false,
        error: 'Title cannot be empty'
      });
    }
    todo.title = title.trim();
  }

  if (completed !== undefined) {
    if (typeof completed !== 'boolean') {
      return res.status(400).json({
        success: false,
        error: 'Completed must be a boolean'
      });
    }
    todo.completed = completed;
  }

  res.status(200).json({
    success: true,
    data: todo
  });
});

// DELETE todo
app.delete('/api/todos/:id', (req, res) => {
  const index = todos.findIndex(t => t.id === parseInt(req.params.id));

  if (index === -1) {
    return res.status(404).json({
      success: false,
      error: 'Todo not found'
    });
  }

  todos.splice(index, 1);

  res.status(204).send(); // No content
});

// 404 handler for undefined routes
app.use((req, res) => {
  res.status(404).json({
    success: false,
    error: 'Route not found'
  });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({
    success: false,
    error: 'Server error'
  });
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});
```

**Testing with curl:**

```bash
# Get all todos
curl http://localhost:3000/api/todos

# Get single todo
curl http://localhost:3000/api/todos/1

# Create todo
curl -X POST http://localhost:3000/api/todos \
  -H "Content-Type: application/json" \
  -d '{"title":"Master MongoDB"}'

# Update todo
curl -X PUT http://localhost:3000/api/todos/1 \
  -H "Content-Type: application/json" \
  -d '{"completed":true}'

# Delete todo
curl -X DELETE http://localhost:3000/api/todos/2
```

**Status codes used:**
- **200**: Success (GET, PUT)
- **201**: Resource created (POST)
- **204**: Success, no content (DELETE)
- **400**: Bad request (validation errors)
- **404**: Not found
- **500**: Server error
